import { useLayoutEffect, type ReactNode } from "react";
import { applyStoredTheme } from "../hooks/useTheme";

interface ThemeProviderProps {
  children: ReactNode;
}

/**
 * Mounts early in the component tree to guarantee the stored theme is applied
 * before the first paint. The module-level `applyStoredTheme()` call in
 * useTheme.ts handles the synchronous pre-render case; this useLayoutEffect
 * covers any edge cases where the module loaded but the DOM changed.
 */
export function ThemeProvider({ children }: ThemeProviderProps) {
  useLayoutEffect(() => {
    applyStoredTheme();
  }, []);

  return <>{children}</>;
}
