export const THEME_IDS = ["t3-dark", "t3-light", "t3-midnight"] as const;
export type ThemeId = (typeof THEME_IDS)[number];

/** Colors covering all semantic UI surfaces for a theme. */
export interface ThemeColors {
  // Core surface colors
  background: string;
  foreground: string;
  card: string;
  cardForeground: string;
  popover: string;
  popoverForeground: string;
  // Brand / interactive
  primary: string;
  primaryForeground: string;
  // Subtle fills
  secondary: string;
