  accent: string;
  accentForeground: string;
  // Semantic
  destructive: string;
  destructiveForeground: string;
  border: string;
  input: string;
  ring: string;
  // Extended surfaces
  sidebar: string;
  sidebarForeground: string;
  sidebarBorder: string;
  editor: string;
