import { useCallback, useEffect, useSyncExternalStore } from "react";
import {
  BUILT_IN_THEMES,
  DEFAULT_THEME_ID,
  getTheme,
  THEME_IDS,
  type ThemeColors,
  type ThemeId,
} from "@t3tools/shared/theme";

export type { ThemeId };
export { BUILT_IN_THEMES, DEFAULT_THEME_ID, THEME_IDS, getTheme };

const STORAGE_KEY = "t3code:color-theme";

// --- External store (module-level, no React context needed) ---

let listeners: Array<() => void> = [];
let lastSnapshot: ThemeId | null = null;

function emitChange(): void {
  for (const listener of listeners) listener();
}

export function getStoredThemeId(): ThemeId {
  const raw = localStorage.getItem(STORAGE_KEY);
  if (THEME_IDS.includes(raw as ThemeId)) return raw as ThemeId;
  // Migrate old "light"/"dark"/"system" values
  if (raw === "light") return "t3-light";
  return DEFAULT_THEME_ID;
}

function getSnapshot(): ThemeId {
  const id = getStoredThemeId();
  if (lastSnapshot === id) return lastSnapshot;
  lastSnapshot = id;
  return id;
}

function subscribe(listener: () => void): () => void {
  listeners.push(listener);

  const handleStorage = (e: StorageEvent): void => {
    if (e.key === STORAGE_KEY) {
      applyStoredTheme(true);
      emitChange();
    }
  };
  window.addEventListener("storage", handleStorage);

  return () => {
    listeners = listeners.filter((l) => l !== listener);
    window.removeEventListener("storage", handleStorage);
  };
}

// --- DOM application ---

function themeToCssVars(colors: ThemeColors): Array<[string, string]> {
  return [
    ["--background", colors.background],
    ["--foreground", colors.foreground],
    ["--card", colors.card],
    ["--card-foreground", colors.cardForeground],
    ["--popover", colors.popover],
    ["--popover-foreground", colors.popoverForeground],
    ["--primary", colors.primary],
    ["--primary-foreground", colors.primaryForeground],
    ["--secondary", colors.secondary],
    ["--secondary-foreground", colors.secondaryForeground],
    ["--muted", colors.muted],
    ["--muted-foreground", colors.mutedForeground],
    ["--accent", colors.accent],
    ["--accent-foreground", colors.accentForeground],
    ["--destructive", colors.destructive],
    ["--destructive-foreground", colors.destructiveForeground],
    ["--border", colors.border],
    ["--input", colors.input],
    ["--ring", colors.ring],
    ["--sidebar", colors.sidebar],
    ["--sidebar-foreground", colors.sidebarForeground],
    ["--sidebar-border", colors.sidebarBorder],
    ["--editor", colors.editor],
    ["--editor-foreground", colors.editorForeground],
    ["--terminal", colors.terminal],
    ["--terminal-foreground", colors.terminalForeground],
    ["--status-bar", colors.statusBar],
    ["--status-bar-foreground", colors.statusBarForeground],
  ];
}

export function applyTheme(id: ThemeId, suppressTransitions = false): void {
  const theme = getTheme(id);
  const el = document.documentElement;

  if (suppressTransitions) {
    el.classList.add("no-transitions");
  }

  // Set color-scheme and dark class
  el.style.colorScheme = theme.colorScheme;
  el.classList.toggle("dark", theme.colorScheme === "dark");
  el.setAttribute("data-theme", id);

  // Apply all CSS custom properties as inline styles (highest priority)
  for (const [prop, value] of themeToCssVars(theme.colors)) {
    el.style.setProperty(prop, value);
  }

  if (suppressTransitions) {
    // Force reflow before removing the suppression class
    // oxlint-disable-next-line no-unused-expressions
    el.offsetHeight;
    requestAnimationFrame(() => {
      el.classList.remove("no-transitions");
    });
  }
}

export function applyStoredTheme(suppressTransitions = false): void {
  applyTheme(getStoredThemeId(), suppressTransitions);
}

// Apply immediately on module load to prevent flash
applyStoredTheme();

// --- React hook ---

export function useTheme() {
  const themeId = useSyncExternalStore(subscribe, getSnapshot);
  const theme = getTheme(themeId);

  const setTheme = useCallback((next: ThemeId) => {
    localStorage.setItem(STORAGE_KEY, next);
    lastSnapshot = next;
    applyTheme(next, true);
    emitChange();
  }, []);

  // Keep DOM in sync on mount/change
  useEffect(() => {
    applyTheme(themeId);
  }, [themeId]);

  return {
    theme: themeId,
    themeDefinition: theme,
    setTheme,
    resolvedColorScheme: theme.colorScheme,
    /** @deprecated use resolvedColorScheme */
    resolvedTheme: theme.colorScheme,
  } as const;
}
