export type ThemeId = (typeof THEME_IDS)[number];

/** Colors covering all semantic UI surfaces for a theme. */
export interface ThemeColors {
  // Core surface colors
  background: string;
  foreground: string;
  card: string;
  cardForeground: string;
  popover: string;
  popoverForeground: string;
  // Brand / interactive
  primary: string;
  primaryForeground: string;
  // Subtle fills
  secondary: string;
  secondaryForeground: string;
  muted: string;
  mutedForeground: string;
  accent: string;
