import { CheckIcon } from "lucide-react";
import { BUILT_IN_THEMES, type ThemeId } from "../../hooks/useTheme";
import { cn } from "../../lib/utils";

interface ThemeSelectorProps {
  value: ThemeId;
  onChange: (id: ThemeId) => void;
}

export function ThemeSelector({ value, onChange }: ThemeSelectorProps) {
  return (
    <div
      className="grid grid-cols-1 gap-3 sm:grid-cols-3"
      role="radiogroup"
      aria-label="Color theme"
    >
      {BUILT_IN_THEMES.map((theme) => {
        const selected = value === theme.id;
        return (
          <button
            key={theme.id}
            type="button"
            role="radio"
            aria-checked={selected}
            onClick={() => onChange(theme.id)}
            className={cn(
              "group relative flex flex-col gap-2 rounded-xl border p-3 text-left transition-all",
              selected
                ? "border-primary/60 ring-2 ring-primary/20"
                : "border-border hover:border-border/80 hover:bg-accent/30",
            )}
          >
            {/* Mini UI preview */}
            <div
              className="overflow-hidden rounded-lg"
              style={{ border: `1px solid ${theme.colors.border}` }}
              aria-hidden="true"
            >
              <div className="flex h-[52px]">
                {/* Sidebar strip */}
                <div
                  className="w-[30%] shrink-0"
                  style={{ backgroundColor: theme.colors.sidebar }}
                >
                  {/* Fake nav items */}
                  <div className="flex flex-col gap-1 p-1.5 pt-2">
                    <div
                      className="h-1.5 rounded-full"
                      style={{
                        backgroundColor: theme.colors.primary,
                        opacity: 0.8,
                        width: "70%",
                      }}
                    />
                    <div
                      className="h-1 rounded-full"
                      style={{
                        backgroundColor: theme.colors.sidebarForeground,
                        opacity: 0.2,
                        width: "55%",
                      }}
                    />
                    <div
                      className="h-1 rounded-full"
                      style={{
                        backgroundColor: theme.colors.sidebarForeground,
                        opacity: 0.15,
                        width: "65%",
                      }}
                    />
                  </div>
                </div>
                {/* Editor / main area */}
                <div
                  className="flex flex-1 flex-col gap-1 p-1.5"
                  style={{ backgroundColor: theme.colors.editor }}
                >
                  <div
                    className="h-1 rounded-full"
                    style={{
                      backgroundColor: theme.colors.editorForeground,
                      opacity: 0.3,
                      width: "80%",
                    }}
                  />
                  <div
                    className="h-1 rounded-full"
                    style={{
                      backgroundColor: theme.colors.primary,
                      opacity: 0.6,
                      width: "55%",
                    }}
                  />
                  <div
                    className="h-1 rounded-full"
                    style={{
                      backgroundColor: theme.colors.editorForeground,
                      opacity: 0.18,
                      width: "70%",
                    }}
                  />
                  <div
                    className="h-1 rounded-full"
                    style={{
                      backgroundColor: theme.colors.editorForeground,
                      opacity: 0.12,
                      width: "40%",
                    }}
                  />
                </div>
              </div>
              {/* Status bar */}
              <div
                className="h-2.5 w-full"
                style={{ backgroundColor: theme.colors.statusBar }}
              />
            </div>

            {/* Color swatches row */}
            <div className="flex gap-1" aria-hidden="true">
              {[
                theme.colors.background,
                theme.colors.sidebar,
                theme.colors.primary,
                theme.colors.editor,
                theme.colors.statusBar,
              ].map((color, i) => (
                <div
                  // eslint-disable-next-line react/no-array-index-key
                  key={i}
                  className="h-3 flex-1 rounded-sm"
                  style={{
                    backgroundColor: color,
                    border: `1px solid ${theme.colors.border}`,
                  }}
                />
              ))}
            </div>

            {/* Label row */}
            <div className="flex items-center justify-between gap-1">
              <span className="text-xs font-medium text-foreground">{theme.label}</span>
              {selected ? (
                <span className="flex items-center gap-0.5 rounded bg-primary/14 px-1 py-0.5 text-[10px] font-medium uppercase tracking-wide text-primary">
                  <CheckIcon className="size-2.5" />
                  On
                </span>
              ) : null}
            </div>
          </button>
        );
      })}
    </div>
  );
}

